    <Stack.Screen name="LoginScreen" component={Login} />
    <Stack.Screen name="FirstAccess" component={FirstAccess} />
    <Stack.Screen name="Example" component={FintechHome} />
    <Stack.Screen name="Home" component={FintechHome} />
    <Stack.Screen name="HomeScreen" component={Example} />
    <Stack.Screen name="PlanDetails" component={Example} />
    <Stack.Screen name="Refuel" component={Example} />

    {FintechCardPlaceRoutes}
  </Stack.Navigator>
);

const Routes = () => {
  return (
    <View style={{ flex: 1 }}>
      <NavigationContainer theme={MainTheme} ref={navigatorRef}>
        {RouteStacks || null}
      </NavigationContainer>
    </View>
  );
};

export default Routes;

